function findResidentByCode(code) {
  return ALL_RESIDENTS.find(resident => resident.code === code) || null;
}

function findResidentsByName(name) {
  const searchTerm = name.toLowerCase();
  return ALL_RESIDENTS.filter(resident => 
    resident.englishName.toLowerCase().includes(searchTerm) ||
    resident.sinhalaNameUnicode.includes(searchTerm) ||
    resident.sinhalaNameFmmalithi.includes(searchTerm)
  );
}

function findResidentsByNationalID(nationalID) {
  return ALL_RESIDENTS.filter(resident => resident.nationalID === nationalID);
}

// For browser environments
if (typeof window !== 'undefined') {
  window.residentDatabase = {
    getAll: getAllResidents,
    findByCode: findResidentByCode,
    findByName: findResidentsByName,
    findByNationalID: findResidentsByNationalID,
    allRecords: ALL_RESIDENTS,
    attendanceRecords: ATTENDANCE_RECORDS,
    recycleBin: RECYCLE_BIN,
    activityLog: ACTIVITY_LOG,
    backupInfo: BACKUP_INFO
  };
}

// For Node.js / ES modules
if (typeof module !== 'undefined' && module.exports) {
  module.exports = {
    ALL_RESIDENTS,
    ATTENDANCE_RECORDS,
    RECYCLE_BIN,
    ACTIVITY_LOG,
    BACKUP_INFO,
    getAllResidents,
    findResidentByCode,
    findResidentsByName,
    findResidentsByNationalID
  };
}
